mapper.select:
SELECT rr.*, sa.area_name, sp.species_name,
       CONCAT(rp.plan_year, '-', rp.plan_season) AS plan_name
FROM release_record rr
LEFT JOIN sea_area sa ON rr.area_id = sa.id
LEFT JOIN species sp ON rr.species_id = sp.id
LEFT JOIN release_plan rp ON rr.plan_id = rp.id


        AND rr.area_id = #{areaId}


        AND rr.species_id = #{speciesId}


        AND rr.release_time >= #{startDate}


        AND rr.release_time <= #{endDate}


ORDER BY rr.created_at DESC
